engineConfig.graphqlSchema:
# --- subgraph: agent_alpha ---
# agent_alpha — seed subgraph for the "Shopify order export" demo agent.
# Synthesized from a 60s screen recording of an operator filtering orders
# and exporting a CSV. Keep in sync with the runtime manifest emitted by
# Gemini 3 Flash (architecture.md §10c) — the generated agent serves this
# SDL from http://agent_alpha:4001/graphql.

extend schema
  @link(
    url: "https://specs.apollo.dev/federation/v2.5"
    import: ["@key", "@shareable", "@tag"]
  )
  @link(
    url: "https://cosmo.wundergraph.com/schemas/edfs/v0.1"
    import: ["@edfs__kafkaSubscribe", "@edfs__kafkaPublish"]
  )

type Order @key(fields: "id") {
  id: ID!
  status: OrderStatus!
  totalCents: Int!
  currency: String!
  placedAt: String!
  customerEmail: String!
  lineItems: [OrderLineItem!]!
}

type OrderLineItem {
  sku: String!
  quantity: Int!
  unitPriceCents: Int!
}

enum OrderStatus {
  PENDING
  PAID
  FULFILLED
  CANCELLED
  REFUNDED
}

input OrderFilter {
  status: OrderStatus
  placedAfter: String
  placedBefore: String
  minTotalCents: Int
}

type OrderExport {
  exportId: ID!
  rowCount: Int!
  signedUrl: String!
  expiresAt: String!
}

type Query {
  orders(filter: OrderFilter, first: Int = 25, after: String): [Order!]!
  order(id: ID!): Order
}

type Mutation {
  exportOrdersCsv(filter: OrderFilter!): OrderExport!
}

# Live fulfilment events — Dream Query registered the topic binding in the
# register_edfs_events step (architecture.md §4).
type Subscription {
  orderStatusChanged(id: ID!): Order!
    @edfs__kafkaSubscribe(topics: ["understudy.agent_alpha.orders"], providerId: "understudy-kafka")
}


# --- subgraph: agent_beta ---
# agent_beta — seed subgraph for the "Salesforce lead enrichment" demo agent.
# Synthesized from a 60s recording of an SDR opening a lead, running a
# lookup, and attaching enrichment notes. Keep in sync with the runtime
# manifest emitted by Gemini 3 Flash (architecture.md §10c) — the
# generated agent serves this SDL from http://agent_beta:4001/graphql.

extend schema
  @link(
    url: "https://specs.apollo.dev/federation/v2.5"
    import: ["@key", "@shareable", "@tag"]
  )
  @link(
    url: "https://cosmo.wundergraph.com/schemas/edfs/v0.1"
    import: ["@edfs__natsSubscribe"]
  )

type Lead @key(fields: "id") {
  id: ID!
  email: String!
  fullName: String!
  company: Company
  score: Int!
  stage: LeadStage!
  enrichments: [Enrichment!]!
  updatedAt: String!
}

type Company @key(fields: "domain") {
  domain: String!
  name: String!
  employeeCount: Int
  industry: String
}

type Enrichment {
  source: EnrichmentSource!
  field: String!
  value: String!
  confidence: Float!
  attachedAt: String!
}

enum EnrichmentSource {
  CLEARBIT
  LINKEDIN
  CRUNCHBASE
  UNDERSTUDY_MEMORY
}

enum LeadStage {
  NEW
  WORKING
  QUALIFIED
  UNQUALIFIED
  CONVERTED
}

input LeadEnrichmentInput {
  leadId: ID!
  includeSources: [EnrichmentSource!]
  minConfidence: Float = 0.6
}

type Query {
  lead(id: ID!): Lead
  searchLeads(query: String!, first: Int = 10): [Lead!]!
}

type Mutation {
  enrichLead(input: LeadEnrichmentInput!): Lead!
}

# NATS subject for live lead updates pushed from the CRM — bound during
# register_edfs_events (architecture.md §4).
type Subscription {
  leadUpdated(id: ID!): Lead!
    @edfs__natsSubscribe(subjects: ["understudy.agent_beta.leads.*"], providerId: "understudy-nats")
}

